def search_quran(patterns, limit=50):
    res=[]
    for item in quran_data:
        text = item['ayah_text']
        norm = normalize_arabic(text)
        for pat in patterns:
            if normalize_arabic(pat) in norm:
                res.append(item)
                break
    return res[:limit]

